local function deserialize_session(serialized_data)
    if not serialized_data or serialized_data == "" then
        return nil
    end
    
    local func, err = loadstring(serialized_data)
    if not func then
        ngx.log(ngx.ERR, "Failed to deserialize session: ", err)
