end

local function serialize_session(session_table)
    if not session_table or type(session_table) ~= "table" then
        return nil
    end
    
    local function serialize_value(v)
        local t = type(v)
        if t == "string" then
            return string.format("%q", v)
        elseif t == "number" or t == "boolean" then
            return tostring(v)
        elseif t == "table" then
            local items = {}
            for key, val in pairs(v) do
                local k = type(key) == "string" and key or "[" .. serialize_value(key) .. "]"
                table.insert(items, k .. "=" .. serialize_value(val))
            end
            return "{" .. table.concat(items, ",") .. "}"
        else
            return "nil"
        end
    end
    
    return "return " .. serialize_value(session_table)
end

